// Auto-Import: wartet bis DB bereit, importiert wenn leer
(function(){
  const DB_NAME='haushalt_db', DB_VERSION=2;
  const req=indexedDB.open(DB_NAME,DB_VERSION);
  req.onupgradeneeded=function(e){
    const db=e.target.result;
    if(!db.objectStoreNames.contains('transactions')){
      const ts=db.createObjectStore('transactions',{keyPath:'id'});
      ts.createIndex('date','date',{unique:false});
      ts.createIndex('type','type',{unique:false});
      ts.createIndex('category','category',{unique:false});
    }
    if(!db.objectStoreNames.contains('months'))db.createObjectStore('months',{keyPath:'id'});
    if(!db.objectStoreNames.contains('settings'))db.createObjectStore('settings',{keyPath:'key'});
  };
  req.onsuccess=function(e){
    const db=e.target.result;
    try{
      const tx=db.transaction('transactions','readonly');
      const c=tx.objectStore('transactions').count();
      c.onsuccess=function(){
        if(c.result===0 && SEED_DATA.length>0){
          console.log('[SEED] DB leer, importiere '+SEED_DATA.length+' Buchungen...');
          const wtx=db.transaction('transactions','readwrite');
          const os=wtx.objectStore('transactions');
          for(var i=0;i<SEED_DATA.length;i++)os.put(SEED_DATA[i]);
          wtx.oncomplete=function(){
            console.log('[SEED] Import fertig! Lade neu...');
            setTimeout(function(){location.reload()},500);
          };
          wtx.onerror=function(ev){console.error('[SEED] Import Fehler',ev.target.error)};
        }else{
          console.log('[SEED] DB hat bereits '+c.result+' Eintraege, kein Import noetig.');
        }
      };
    }catch(ex){console.error('[SEED] Fehler',ex)}
  };
})();

